const testimony = [
  {
    id: 1,
    name: "Clark Emet",
    feedback: "Their Bruschetta was absolutely delicious! I will come back!",
    image: require("../images/Clark-Emet.jpg"),
  },
  {
    id: 2,
    name: "Janet Okwo",
    feedback: "I like the lemon dessert. Highly recommend!",
    image: require("../images/Janet-Okwo.jpg"),
  },
  {
    id: 3,
    name: "Frank Molet",
    feedback: "The setting is warm, magnificent and the food excellent.",
    image: require("../images/Frank-Molet.jpg"),
  },
];

export default testimony;
